package main

import (
	"encoding/xml"
	"fmt"
)

type Config struct {
	XMLName xml.Name `xml:"configuration"`
	Settings []Setting `xml:"setting"`
}

type Setting struct {
	Name  string `xml:"name,attr"`
	Value string `xml:"value,attr"`
}

func parseConfig(data []byte) (*Config, error) {
	var config Config
	err := xml.Unmarshal(data, &config)
	if err != nil {
		return nil, err
	}
	return &config, nil
}

func main() {
	xmlData := []byte(`
<configuration>
    <setting name="host" value="localhost"/>
    <setting name="port" value="8080"/>
</configuration>`)
	
	config, err := parseConfig(xmlData)
	if err != nil {
		fmt.Println("Error parsing XML:", err)
		return
	}

	for _, setting := range config.Settings {
		fmt.Printf("%s: %s\n", setting.Name, setting.Value)
	}
}